Here's a complete example with both `DataRow` and `DynamicData` approaches:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- DataRow: inline constant values ---

    [TestMethod]
    [DataRow(1, 10.00, 10.00)]
    [DataRow(3, 5.50, 16.50)]
    [DataRow(0, 99.99, 0.00)]
    [DataRow(1, 0.00, 0.00)]
    public void CalculateTotal_ReturnsExpected(int quantity, double price, double expected)
    {
        var result = _calculator.CalculateTotal(quantity, (decimal)price);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1, 10.00)]
    [DataRow(1, -5.00)]
    public void CalculateTotal_InvalidInputs_Throws(int quantity, double price)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(quantity, (decimal)price));
    }

    // --- DynamicData: complex/computed test cases ---

    [TestMethod]
    [DynamicData(nameof(DiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_ReturnsExpected(
        decimal total, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(total, discountPercent);
        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> DiscountCases()
    {
        yield return new object[] { 100m, 0m,    100m   };
        yield return new object[] { 100m, 10m,   90m    };
        yield return new object[] { 100m, 100m,  0m     };
        yield return new object[] { 250m, 25m,   187.50m };
        yield return new object[] { 0m,   50m,   0m     };
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_InvalidPercent_Throws(
        decimal total, decimal discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(total, discountPercent));
    }

    private static IEnumerable<object[]> InvalidDiscountCases()
    {
        yield return new object[] { 100m, -1m  };
        yield return new object[] { 100m, 101m };
    }
}
```

**Key points:**

- **`DataRow`** — best for simple inline constants; note `decimal` isn't allowed in attributes, so use `double` and cast.
- **`DynamicData`** — use when you need `decimal` precision, complex objects, or computed values. Point it at a `static` method (or property) returning `IEnumerable<object[]>`.
- **`TestInitialize`** — creates a fresh instance per test, avoiding shared state.
- **Separate negative tests** — invalid inputs get their own methods asserting exceptions, keeping happy-path tests clean.

Adjust the method signatures and exception types to match your actual `PriceCalculator` implementation.
